class Solution:
    def new21Game(self, n, k, maxPts):
        if k == 0 or n >= k - 1 + maxPts:
            return 1.0
        # straightforward DP: prob[x] = probability of reaching total x
        prob = [0.0] * (k + maxPts)
        prob[0] = 1.0
        ans = 0.0
        for x in range(k):
            p = prob[x]
            if p == 0.0:
                continue
            share = p / maxPts
            for d in range(1, maxPts + 1):
                prob[x + d] += share
        for x in range(k, k + maxPts):
            if x <= n:
                ans += prob[x]
        return ans

