class Solution:
    def new21Game(self, n, k, maxPts):
        if k == 0 or n >= k - 1 + maxPts:
            return 1.0
        dp = [0.0] * (n + 1)
        dp[0] = 1.0
        window = 1.0
        ans = 0.0
        for x in range(1, n + 1):
            dp[x] = window / maxPts
            if x < k:
                window += dp[x]
            else:
                ans += dp[x]
            if x - maxPts >= 0 and x - maxPts < k:
                window -= dp[x - maxPts]
        return ans

