var new21Game = function(n, k, maxPts) {
    if (k === 0 || n >= k - 1 + maxPts) return 1.0;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1.0;
    let window = 1.0;
    let ans = 0.0;
    for (let x = 1; x <= n; x++) {
        dp[x] = window / maxPts;
        if (x < k) {
            window += dp[x];
        } else {
            ans += dp[x];
        }
        if (x - maxPts >= 0 && x - maxPts < k) {
            window -= dp[x - maxPts];
        }
    }
    return ans;
};
